const data = $json;

// Use pre-resolved tone-adaptive SMS body from StrydeOS when available.
// Falls back to legacy inline templates for backwards compatibility.
if (data.resolvedSmsBody) {
  return [{ ...data, smsBody: data.resolvedSmsBody, toNumber: data.patientPhone }];
}

// Legacy fallback (remove once all payloads include resolvedSmsBody)
const type = data.sequenceType;
const messages = {
  rebooking_prompt: `Hi ${data.patientFirstName ?? 'there'}, we noticed you haven't booked your next appointment at ${data.clinicName}. Staying on track with your sessions helps you recover faster. Book now: ${data.bookingUrl ?? data.clinicUrl ?? ''}`,
  hep_reminder: `Hi ${data.patientFirstName ?? 'there'}, your next session at ${data.clinicName} is coming up. Have you been keeping up with your exercises? Completing them makes a real difference to your recovery.`,
  review_prompt: `Hi ${data.patientFirstName ?? 'there'}, thank you for choosing ${data.clinicName}. We'd love to hear how your experience was. Leave a quick review: ${data.reviewUrl ?? data.googleReviewUrl ?? ''}`
};

return [{
  ...data,
  smsBody: messages[type] ?? `Hi, this is a reminder from ${data.clinicName}.`,
  toNumber: data.patientPhone,
}];
